SELECT id, title, category, photographer, date, url, description, status, created_at, updated_at,
FROM image
AND title LIKE CONCAT('%', #{title}, '%')
AND category = #{category}
AND date >= #{startDate}
AND date <= #{endDate}
AND CASE status WHEN 0 THEN 'pending' WHEN 1 THEN 'approved' WHEN 2 THEN 'rejected' WHEN 3 THEN 'published' WHEN 4 THEN 'draft' ELSE 'unknown' END = #{statusStr}
ORDER BY date DESC
ORDER BY date ASC
ORDER BY created_at DESC
ORDER BY created_at ASC
ORDER BY created_at DESC

